-- WS3 hardware: Hafele + Blum + Salice runners/hinges/plates (trade net ex GST).
-- Source: hardware-target-list.csv (session capture, verified on supplier portals).
create unique index if not exists idx_hardware_pricing_item_code on public.hardware_pricing(item_code);
on conflict (item_code) do update set
  name = excluded.name, hardware_type = excluded.hardware_type, brand = excluded.brand,
  series = excluded.series, runner_height = excluded.runner_height, runner_depth = excluded.runner_depth,
  unit_cost = excluded.unit_cost, visibility_status = excluded.visibility_status, updated_at = now();
